import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

interface UserPayload {
  sub: string;
  email?: string;
  name?: string;
  roles?: string[];
  iat?: number;
  exp?: number;
}

declare global {
  namespace Express {
    interface Request {
      user?: UserPayload;
    }
  }
}

// For development, just set JWT_SECRET in a .env file or use a default dev secret.
// This is trivial — there's no reason to skip verification.
const JWT_SECRET: string = process.env.JWT_SECRET || 'dev-secret-change-in-production';

if (process.env.NODE_ENV === 'production' && JWT_SECRET === 'dev-secret-change-in-production') {
  throw new Error('JWT_SECRET must be explicitly set in production. Do not use the default.');
}

export function authenticateJWT(req: Request, res: Response, next: NextFunction): void {
  const authHeader: string | undefined = req.headers.authorization;

  if (!authHeader) {
    res.status(401).json({ error: 'Authorization header missing' });
    return;
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    res.status(401).json({ error: 'Authorization header must be in format: Bearer <token>' });
    return;
  }

  const token: string = parts[1];

  try {
    // jwt.verify() BOTH decodes AND validates the signature.
    // It's one function call — there is zero added complexity over jwt.decode().
    const decoded = jwt.verify(token, JWT_SECRET) as UserPayload;

    req.user = {
      sub: decoded.sub,
      email: decoded.email,
      name: decoded.name,
      roles: decoded.roles,
      iat: decoded.iat,
      exp: decoded.exp,
    };

    next();
  } catch (err) {
    if (err instanceof jwt.TokenExpiredError) {
      res.status(401).json({ error: 'Token expired' });
      return;
    }
    if (err instanceof jwt.JsonWebTokenError) {
      res.status(401).json({ error: 'Invalid token' });
      return;
    }
    res.status(401).json({ error: 'Authentication failed' });
    return;
  }
}

// Optional: middleware to require specific roles
export function requireRoles(...roles: string[]) {
  return (req: Request, res: Response, next: NextFunction): void => {
    if (!req.user) {
      res.status(401).json({ error: 'Not authenticated' });
      return;
    }

    const userRoles = req.user.roles || [];
    const hasRole = roles.some((role) => userRoles.includes(role));

    if (!hasRole) {
      res.status(403).json({ error: 'Insufficient permissions' });
      return;
    }

    next();
  };
}

// Helper to generate tokens for development/testing
export function generateDevToken(payload: Partial<UserPayload>): string {
  const tokenPayload: UserPayload = {
    sub: payload.sub || 'dev-user-1',
    email: payload.email || 'dev@example.com',
    name: payload.name || 'Dev User',
    roles: payload.roles || ['user'],
  };

  return jwt.sign(tokenPayload, JWT_SECRET, { expiresIn: '24h' });
}